{"file_path":"/project/ktlint-ruleset-standard/src/main/kotlin/com/pinterest/ktlint/ruleset/standard/rules/LegacySuppressDirectiveRule.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.ruleset.standard.StandardRule
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.PsiComment

/**
 * Flags usages of the legacy `ktlint-disable` / `ktlint-enable` directives which used to suppress rules via comments. Those directives are
 * no longer supported and must be replaced with `@Suppress` annotations.
 */
public class LegacySuppressDirectiveRule :
    StandardRule(id = "legacy-suppress-directive") {
    override val isSuppressionAllowed: Boolean = false

    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val psiComment = node.psi as? PsiComment ?: return
        val legacyDirective = psiComment.text.findLegacyDirective() ?: return
        emit(
            node.startOffset,
            "Directive '$legacyDirective' is no longer supported. Replace it with an @Suppress annotation (e.g. @Suppress(\"ktlint:rule-set-id:rule-id\")).",
            false,
        )
    }

    private fun String.findLegacyDirective(): String? =
        when {
            contains(KTLINT_DISABLE_DIRECTIVE) -> KTLINT_DISABLE_DIRECTIVE
            contains(KTLINT_ENABLE_DIRECTIVE) -> KTLINT_ENABLE_DIRECTIVE
            else -> null
        }

    private companion object {
        const val KTLINT_DISABLE_DIRECTIVE = "ktlint-disable"
        const val KTLINT_ENABLE_DIRECTIVE = "ktlint-enable"
    }
}

public val LEGACY_SUPPRESS_DIRECTIVE_RULE_ID: RuleId = LegacySuppressDirectiveRule().ruleId
"}

{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/LegacySuppressDirectiveRuleTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class LegacySuppressDirectiveRuleTest {
    private val legacySuppressDirectiveRuleAssertThat = assertThatRule { LegacySuppressDirectiveRule() }

    @Test
    fun `Given an EOL legacy directive then report a violation`() {
        val code =
            """
            // ktlint-disable
            val foo = "foo"
            """.trimIndent()

        legacySuppressDirectiveRuleAssertThat(code)
            .hasLintViolationWithoutAutoCorrect(1, 1, "Directive 'ktlint-disable' is no longer supported. Replace it with an @Suppress annotation (e.g. @Suppress(\"ktlint:rule-set-id:rule-id\")).")
    }

    @Test
    fun `Given a block legacy directive then report a violation`() {
        val code =
            """
            /* ktlint-enable some-rule */
            val foo = "foo"
            """.trimIndent()

        legacySuppressDirectiveRuleAssertThat(code)
            .hasLintViolationWithoutAutoCorrect(1, 1, "Directive 'ktlint-enable' is no longer supported. Replace it with an @Suppress annotation (e.g. @Suppress(\"ktlint:rule-set-id:rule-id\")).")
    }

    @Test
    fun `Given a file in which all rules are suppressed via annotation then still report legacy directives`() {
        val code =
            """
            @file:Suppress("ktlint")

            /* ktlint-disable */
            val foo = "foo"
            """.trimIndent()

        legacySuppressDirectiveRuleAssertThat(code)
            .hasLintViolationWithoutAutoCorrect(3, 1, "Directive 'ktlint-disable' is no longer supported. Replace it with an @Suppress annotation (e.g. @Suppress(\"ktlint:rule-set-id:rule-id\")).")
    }
}
"}

